def solve():
    n = int(input())
    a = list(map(int, input().split()))
    a_set = set(a)

    def differences(b):
        return set(x - y for x in b for y in b)

    def backtrack(b):
        diffs = differences(b)
        if len(b) == n:
            if a_set <= diffs:
                return True
            return False
        # If already covers all, we can still add more elements (no-op additions possible)
        # but we need exactly n elements, so continue
        if a_set <= diffs:
            # We can pad with duplicate elements (differences won't change)
            return True
        # Generate candidates
        uncovered = a_set - diffs
        # Pick one uncovered element, try to cover it
        target = next(iter(uncovered))
        candidates = set()
        for bk in b:
            candidates.add(target + bk)  # new - bk = target => new = target + bk
            candidates.add(bk - target)  # bk - new = target => new = bk - target
        for c in candidates:
            if backtrack(b + [c]):
                return True
        return False

    print("YES" if backtrack([0]) else "NO")

t = int(input())
for _ in range(t):
    solve()
